CREATE TABLE IF NOT EXISTS candles (symbol VARCHAR(20) NOT NULL, timeframe VARCHAR(5) NOT NULL, ts TIMESTAMPTZ NOT NULL, open NUMERIC(20,8), high NUMERIC(20,8), low NUMERIC(20,8), close NUMERIC(20,8), volume NUMERIC(24,4), quote_volume NUMERIC(24,4) DEFAULT 0, is_closed BOOLEAN DEFAULT TRUE, PRIMARY KEY (symbol, timeframe, ts));
CREATE TABLE IF NOT EXISTS open_interest (symbol VARCHAR(20) NOT NULL, ts TIMESTAMPTZ NOT NULL, oi_value NUMERIC(24,4), oi_change_pct NUMERIC(10,4) DEFAULT 0, PRIMARY KEY (symbol, ts));
CREATE TABLE IF NOT EXISTS funding_rates (symbol VARCHAR(20) NOT NULL, ts TIMESTAMPTZ NOT NULL, funding_rate NUMERIC(14,8), mark_price NUMERIC(20,8) DEFAULT 0, PRIMARY KEY (symbol, ts));
CREATE TABLE IF NOT EXISTS trades_aggregated (symbol VARCHAR(20) NOT NULL, ts TIMESTAMPTZ NOT NULL, buy_vol NUMERIC(24,4) DEFAULT 0, sell_vol NUMERIC(24,4) DEFAULT 0, PRIMARY KEY (symbol, ts));
CREATE TABLE IF NOT EXISTS ticker_latest (symbol VARCHAR(20) PRIMARY KEY, ts TIMESTAMPTZ NOT NULL, price NUMERIC(20,8), volume_24h NUMERIC(24,4) DEFAULT 0, high_24h NUMERIC(20,8) DEFAULT 0, low_24h NUMERIC(20,8) DEFAULT 0);
CREATE TABLE IF NOT EXISTS symbols (symbol VARCHAR(20) PRIMARY KEY, base_asset VARCHAR(10), volume_rank INTEGER DEFAULT 9999, is_active BOOLEAN DEFAULT TRUE);
CREATE INDEX IF NOT EXISTS idx_candles ON candles (symbol, timeframe, ts DESC);
CREATE INDEX IF NOT EXISTS idx_oi ON open_interest (symbol, ts DESC);
CREATE INDEX IF NOT EXISTS idx_funding ON funding_rates (symbol, ts DESC);
GRANT ALL ON ALL TABLES IN SCHEMA public TO axonize;
GRANT ALL ON ALL SEQUENCES IN SCHEMA public TO axonize;
